@app.route('/dump', methods=['POST'])
def dump_file():
    """Upload a single file"""
    if 'file' not in request.files:
        return jsonify({'error': 'No file'}), 400

    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'Empty filename'}), 400

    # Get metadata
    case_id = request.form.get('case_id', 'unknown')
    category = request.form.get('category', 'uncategorized')
    source = request.form.get('source', 'unknown')
    notes = request.form.get('notes', '')

    # Generate safe filename
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    original_name = secure_filename(file.filename)
    file_id = str(uuid.uuid4())[:8]

    # Create case folder
    case_folder = os.path.join(UPLOAD_FOLDER, case_id)
    os.makedirs(case_folder, exist_ok=True)

    # Save file
    saved_name = f"{timestamp}_{file_id}_{original_name}"
    filepath = os.path.join(case_folder, saved_name)
    file.save(filepath)

    # Calculate hash
    sha256_hash = hashlib.sha256()
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(4096), b""):
            sha256_hash.update(chunk)
    file_hash = sha256_hash.hexdigest()

    # Create metadata file
    meta = {
        'original_name': original_name,
        'saved_name': saved_name,
        'file_id': file_id,
        'case_id': case_id,
        'category': category,
        'source': source,
        'notes': notes,
        'sha256': file_hash,
        'size': os.path.getsize(filepath),
        'uploaded_at': datetime.now().isoformat(),
        'path': filepath
    }

    meta_path = os.path.join(case_folder, f"{saved_name}.json")
    import json
    with open(meta_path, 'w') as f:
        json.dump(meta, f, indent=2)

    return jsonify({
        'success': True,
        'file_id': file_id,
        'filename': saved_name,
        'original_name': original_name,
        'hash': file_hash[:16],
        'size': meta['size'],
        'case': case_id
    })

@app.route('/download/<path:filename>')
def download(filename):
    """Download a file"""
    # Find file in any case folder
    for root, dirs, files in os.walk(UPLOAD_FOLDER):
        if filename in files:
            return send_from_directory(root, filename, as_attachment=True)
    return jsonify({'error': 'File not found'}), 404

@app.route('/list')
def list_files():
    """List all dumped files"""
    files = []
    for root, dirs, filenames in os.walk(UPLOAD_FOLDER):
        for f in filenames:
            if f.endswith('.json'):
                continue
            filepath = os.path.join(root, f)
            rel_path = os.path.relpath(filepath, UPLOAD_FOLDER)
            files.append({
                'name': f,
                'path': rel_path,
                'size': os.path.getsize(filepath),
                'modified': datetime.fromtimestamp(os.path.getmtime(filepath)).isoformat()
            })

    return jsonify({
        'count': len(files),
        'files': files
    })

@app.route('/stats')
def stats():
    """Get dump statistics"""
    total_files = 0
    total_size = 0
    cases = set()

    for root, dirs, files in os.walk(UPLOAD_FOLDER):
        case_name = os.path.basename(root)
        if case_name != 'dumps':
            cases.add(case_name)

        for f in files:
            if not f.endswith('.json'):
                total_files += 1
                total_size += os.path.getsize(os.path.join(root, f))

    return jsonify({
        'total_files': total_files,
        'total_size_mb': round(total_size / 1024 / 1024, 2),
        'cases': len(cases),
        'case_list': list(cases)
    })

