    <script>
        let selectedFiles = [];

        document.getElementById('dropZone').addEventListener('click', () => document.getElementById('fileInput').click());
        document.getElementById('fileInput').addEventListener('change', (e) => addFiles(e.target.files));

        ['dragover', 'dragleave', 'drop'].forEach(event => {
            document.getElementById('dropZone').addEventListener(event, (e) => {
                e.preventDefault();
                if (event === 'dragover') document.getElementById('dropZone').classList.add('dragover');
                else document.getElementById('dropZone').classList.remove('dragover');
                if (event === 'drop') addFiles(e.dataTransfer.files);
            });
        });

        function addFiles(files) {
            let totalSize = selectedFiles.reduce((sum, f) => sum + f.file.size, 0);

            for (let file of files) {
                if (file.size > 100 * 1024 * 1024) {
                    alert('File too large: ' + file.name + ' (max 100MB)');
                    continue;
                }
                totalSize += file.size;
                if (totalSize > 500 * 1024 * 1024) {
                    alert('Total size would exceed 500MB limit');
                    break;
                }
                selectedFiles.push({ file, id: Math.random().toString(36).substr(2, 9), status: 'pending' });
            }
            updateFileList();
        }

        function updateFileList() {
            document.getElementById('fileCount').textContent = selectedFiles.length;
            document.getElementById('fileList').classList.add('show');
            document.getElementById('metaForm').style.display = selectedFiles.length > 0 ? 'block' : 'none';

            document.getElementById('fileItems').innerHTML = selectedFiles.map(item => `
                <div class="file-item" id="file-${item.id}">
                    <span class="file-name">📄 ${item.file.name}</span>
                    <span class="file-size">${formatSize(item.file.size)}</span>
                    <span class="file-status status-${item.status}">${item.status}</span>
                </div>
            `).join('');
        }

        function formatSize(bytes) {
            if (bytes === 0) return '0 B';
            const k = 1024;
            const sizes = ['B', 'KB', 'MB', 'GB'];
            const i = Math.floor(Math.log(bytes) / Math.log(k));
            return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
        }

        async function startUpload() {
            const btn = document.getElementById('uploadBtn');
            btn.disabled = true;
            btn.textContent = '⏳ UPLOADING...';

            const caseId = document.getElementById('caseId').value || 'unknown-case';
            const category = document.getElementById('category').value;
            const source = document.getElementById('source').value;
            const notes = document.getElementById('notes').value;

            const results = [];

            for (let item of selectedFiles) {
                item.status = 'uploading';
                updateFileStatus(item.id, 'uploading', 'Uploading...');

                const formData = new FormData();
                formData.append('file', item.file);
                formData.append('case_id', caseId);
                formData.append('category', category);
                formData.append('source', source);
                formData.append('notes', notes);

                try {
                    const response = await fetch('/dump', { method: 'POST', body: formData });
                    const result = await response.json();

                    if (result.success) {
                        item.status = 'done';
                        updateFileStatus(item.id, 'done', '✅ Done');
                        results.push(result);
                    } else {
                        item.status = 'error';
                        updateFileStatus(item.id, 'error', '❌ ' + (result.error || 'Failed'));
                    }
                } catch (err) {
                    item.status = 'error';
                    updateFileStatus(item.id, 'error', '❌ Error');
                }
            }

            showResults(results);
            btn.disabled = false;
            btn.textContent = '🚀 UPLOAD ALL FILES';
        }

        function updateFileStatus(id, status, text) {
            const el = document.getElementById(`file-${id}`);
            if (el) {
                el.querySelector('.file-status').textContent = text;
                el.querySelector('.file-status').className = `file-status status-${status}`;
            }
        }

        function showResults(results) {
            const success = results.filter(r => r.success);
            document.getElementById('resultContent').innerHTML = `
                <p><strong>${success.length}/${results.length} files uploaded successfully</strong></p>
                <div style="margin-top: 15px;">
                    ${success.map(r => `
                        <div style="margin: 10px 0; padding: 10px; background: #0d1f0d; border-radius: 5px;">
                            <div>📄 ${r.original_name}</div>
                            <div style="font-size: 12px; color: #888; margin-top: 5px;">
                                ID: ${r.file_id} | Hash: ${r.hash}
                            </div>
                        </div>
                    `).join('')}
                </div>
            `;
            document.getElementById('results').classList.add('show');
        }
    </script>
</body>
