@login_required
def dump_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400

    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'Empty filename'}), 400

    if not allowed_file(file.filename):
        return jsonify({'error': 'File type not allowed'}), 400

    # Check file size
    file.seek(0, 2)
    file_size = file.tell()
    file.seek(0)

    if file_size > MAX_FILE_SIZE:
        return jsonify({'error': f'File too large (max {MAX_FILE_SIZE/1024/1024}MB)'}), 400

    # Get metadata
    case_id = secure_filename(request.form.get('case_id', 'unknown'))
    category = request.form.get('category', 'uncategorized')
    source = request.form.get('source', 'unknown')
    notes = request.form.get('notes', '')

    # Generate safe filename
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    original_name = secure_filename(file.filename)
    file_id = str(uuid.uuid4())[:8]

    # Create case folder structure
    case_folder = os.path.join(UPLOAD_FOLDER, case_id, category)
    os.makedirs(case_folder, exist_ok=True)

    # Save file
    saved_name = f"{timestamp}_{file_id}_{original_name}"
    filepath = os.path.join(case_folder, saved_name)
    file.save(filepath)

    # Calculate hash
    sha256_hash = hashlib.sha256()
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(4096), b""):
            sha256_hash.update(chunk)
    file_hash = sha256_hash.hexdigest()

    # Create metadata
    import json
    meta = {
        'original_name': original_name,
        'saved_name': saved_name,
        'file_id': file_id,
        'case_id': case_id,
        'category': category,
        'source': source,
        'notes': notes,
        'sha256': file_hash,
        'size': file_size,
        'uploaded_by': 'authenticated_user',
        'uploaded_at': datetime.now().isoformat(),
        'path': filepath
    }

    meta_path = os.path.join(case_folder, f"{saved_name}.json")
    with open(meta_path, 'w') as f:
        json.dump(meta, f, indent=2)

    return jsonify({
        'success': True,
        'file_id': file_id,
        'filename': saved_name,
        'original_name': original_name,
        'hash': file_hash[:16] + '...',
        'size': file_size,
        'case': case_id
    })

@app.route('/stats')
@login_required
def stats():
    total_files = 0
    total_size = 0
    cases = set()

    for root, dirs, files in os.walk(UPLOAD_FOLDER):
        rel_path = os.path.relpath(root, UPLOAD_FOLDER)
        if rel_path != '.' and '/' not in rel_path:
            cases.add(rel_path)

        for f in files:
            if not f.endswith('.json'):
                total_files += 1
                total_size += os.path.getsize(os.path.join(root, f))

    return jsonify({
        'total_files': total_files,
        'total_size_mb': round(total_size / 1024 / 1024, 2),
        'cases': len(cases),
        'case_list': list(cases)
    })

